{"code":"import json
import re

# Helper to load data
def load_data(var_val):
    if isinstance(var_val, str):
        # Assume it's a file path
        with open(var_val, 'r') as f:
            return json.load(f)
    else:
        # Assume it's the data list
        return var_val

# Load metadata
meta_var = locals()['var_function-call-12987280970809318212']
meta_list = load_data(meta_var)

# Load articles
art_var = locals()['var_function-call-10227214225653299707']
art_list = load_data(art_var)

# Create a mapping from article_id to year
# Filter for 2010-2020
id_to_year = {}
for m in meta_list:
    aid = int(m['article_id'])
    date = m['publication_date'] # "YYYY-MM-DD"
    year = int(date[:4])
    if 2010 <= year <= 2020:
        id_to_year[aid] = year

# Categories keywords
categories = {
    'Business': ['business', 'economy', 'market', 'financial', 'stock', 'share', 'trade', 'investment', 'bank', 'money', 'price', 'profit', 'loss', 'corp', 'tax', 'rate', 'dollar', 'euro', 'yen', 'budget', 'debt', 'inflation', 'recession', 'growth', 'sale', 'deal', 'merger', 'acquisition', 'industry', 'commercial', 'wall street', 'dow', 'nasdaq', 'oil', 'gas', 'energy', 'bonds', 'futures', 'forex', 'ceo', 'cfo', 'fed', 'treasury', 'imf', 'wto', 'opec', 'sector', 'retail', 'spending', 'job', 'unemployment'],
    'Sports': ['sport', 'game', 'team', 'cup', 'league', 'player', 'match', 'win', 'score', 'olympic', 'football', 'soccer', 'baseball', 'basketball', 'tennis', 'golf', 'coach', 'champion', 'tournament', 'medal', 'athlete', 'race', 'f1', 'nfl', 'nba', 'mlb', 'nhl', 'stadium', 'club'],
    'SciTech': ['science', 'technology', 'tech', 'computer', 'software', 'hardware', 'internet', 'web', 'space', 'nasa', 'study', 'research', 'virus', 'phone', 'mobile', 'apple', 'google', 'microsoft', 'biotech', 'robot', 'astronomy', 'physics', 'biology', 'experiment', 'discovery', 'launch', 'orbit', 'mars', 'moon', 'online', 'data', 'cyber', 'network', 'digital'],
    'World': ['world', 'war', 'peace', 'election', 'president', 'minister', 'attack', 'bomb', 'kill', 'government', 'police', 'court', 'law', 'china', 'russia', 'iran', 'iraq', 'uk', 'france', 'germany', 'eu', 'un', 'nation', 'military', 'army', 'conflict', 'treaty', 'protest', 'vote', 'parliament', 'official', 'state', 'security', 'terror', 'bombing', 'refugee', 'strike', 'rebel']
}

def classify(text):
    text = text.lower()
    scores = {cat: 0 for cat in categories}
    for cat, kws in categories.items():
        for kw in kws:
            if re.search(r'\b' + re.escape(kw) + r'\b', text):
                scores[cat] += 1

    # Get max score
    if all(v == 0 for v in scores.values()):
        return 'World' # Default if nothing matches
    max_cat = max(scores, key=scores.get)
    return max_cat

# Count business articles per year
year_counts = {y: 0 for y in range(2010, 2021)}

business_count = 0
processed_count = 0

for art in art_list:
    aid = int(art['article_id'])
    if aid in id_to_year:
        title = art.get('title', '')
        desc = art.get('description', '')
        full_text = title + " " + desc

        cat = classify(full_text)
        if cat == 'Business':
            y = id_to_year[aid]
            year_counts[y] += 1
            business_count += 1
        processed_count += 1

# Calculate average
total_years = 11 # 2010 to 2020 inclusive
avg_per_year = business_count / total_years

print("__RESULT__:")
print(json.dumps({"year_counts": year_counts, "processed": processed_count, "total_business": business_count, "average": avg_per_year}))"}

